const active = $('Active properties').all().map(i => i.json);
const overdue = $('Overdue jobs').all().map(i => i.json);
const pending = $('Pending invoices').all().map(i => i.json);

const lines = [];
lines.push(`*RehabOps daily digest — ${new Date().toLocaleDateString()}*`);
lines.push('');
lines.push(`*${active.length} active properties*`);
for (const p of active.slice(0, 10)) {
  lines.push(`  • ${p.address} — ${p.status} (${p.pct}% of budget)`);
}
lines.push('');
lines.push(`*${overdue.length} overdue jobs*`);
for (const j of overdue.slice(0, 10)) {
  lines.push(`  • ${j.title} @ ${j.address} (${j.company_name ?? 'unassigned'}) — was due ${j.due_date}`);
}
lines.push('');
lines.push(`*${pending.length} pending invoices*`);
for (const i of pending.slice(0, 10)) {
  lines.push(`  • ${i.company_name} — $${i.amount} (${i.invoice_number ?? 'no #'}) for ${i.title}`);
}

return [{ json: { text: lines.join('\n'), counts: { active: active.length, overdue: overdue.length, pending: pending.length } } }];
